files['drawable_ic_launcher_foreground.xml'] = '<?xml version="1.0" encoding="utf-8"?>\n<!-- Sujood app icon foreground: white onion dome + crescent on teal bg -->\n<vector xmlns:android="http://schemas.android.com/apk/res/android"\n    android:width="108dp"\n    android:height="108dp"\n    android:viewportWidth="108"\n    android:viewportHeight="108">\n\n    <!--\n        Onion dome shape: starts wide at base (y=76), curves in,\n        then bulges out (the "onion" belly), tapers to a thin neck,\n        then ends at a pointed finial tip (y=28).\n        Drawn as a single filled path.\n    -->\n    <path\n        android:fillColor="#FFFFFF"\n        android:pathData="\n            M54,28\n            C54,28 52,30 51,32\n            C50,34 51,36 54,38\n            C57,36 58,34 57,32\n            C56,30 54,28 54,28 Z\n\n            M54,38\n            C50,38 44,42 40,50\n            C36,58 35,64 35,68\n            C35,70 36,72 38,73\n            L70,73\n            C72,72 73,70 73,68\n            C73,64 72,58 68,50\n            C64,42 58,38 54,38 Z\n        "/>\n\n    <!-- Crescent moon above the finial -->\n    <!-- Outer circle of crescent -->\n    <path\n        android:fillColor="#FFFFFF"\n        android:pathData="M54,18 m-6,0 a6,6 0 1,0 12,0 a6,6 0 1,0 -12,0"/>\n    <!-- Inner cutout to form crescent (background colour = #0D2233) -->\n    <path\n        android:fillColor="#0D2233"\n        android:pathData="M56.5,16 m-5,0 a5,5 0 1,0 10,0 a5,5 0 1,0 -10,0"/>\n\n</vector>\n'

files['drawable_ic_prayer_icon.xml'] = '<?xml version="1.0" encoding="utf-8"?>\n<vector xmlns:android="http://schemas.android.com/apk/res/android"\n    android:width="120dp"\n    android:height="120dp"\n    android:viewportWidth="120"\n    android:viewportHeight="120">\n\n    <!-- Onion dome body -->\n    <path\n        android:fillColor="#FFFFFF"\n        android:pathData="\n            M60,32\n            C60,32 58,34 57,37\n            C56,40 57,42 60,44\n            C63,42 64,40 63,37\n            C62,34 60,32 60,32 Z\n\n            M60,44\n            C55,44 48,49 44,58\n            C40,67 38,74 38,79\n            C38,82 40,84 43,85\n            L77,85\n            C80,84 82,82 82,79\n            C82,74 80,67 76,58\n            C72,49 65,44 60,44 Z\n        "/>\n\n    <!-- Crescent -->\n    <path\n        android:fillColor="#FFFFFF"\n        android:pathData="M60,20 m-7,0 a7,7 0 1,0 14,0 a7,7 0 1,0 -14,0"/>\n    <path\n        android:fillColor="#101322"\n        android:pathData="M63,18 m-6,0 a6,6 0 1,0 12,0 a6,6 0 1,0 -12,0"/>\n\n</vector>\n'

